// Role-based permission system for PMI Tools

export type Role = 'superadmin' | 'admin' | 'lead_instructor' | 'agency_liaison' | 'instructor' | 'program_director' | 'volunteer_instructor' | 'agency_observer' | 'student' | 'guest' | 'pending';

export const ROLE_LEVELS: Record<Role, number> = {
  superadmin: 5,
  admin: 4,
  lead_instructor: 3,
  agency_liaison: 2.5,       // Agency teaching staff — full read/write on scoped programs (e.g., LVFR AEMT)
  instructor: 2,
  program_director: 1.75,    // Affiliations access only — non-instructor campus staff
  volunteer_instructor: 1.5, // Can access scheduling and lab schedule (read-only), no student data
  agency_observer: 1.25,     // Agency read-only staff (e.g., Training Captain) — read scoped program data only
  student: 1,                // Student portal access only
  guest: 1,                  // Guest access (same level as student)
  pending: 0,                // Minimal access - new users awaiting approval
};

export const ROLE_LABELS: Record<Role, string> = {
  superadmin: 'Super Admin',
  admin: 'Admin',
  lead_instructor: 'Lead Instructor',
  agency_liaison: 'Agency Liaison',
  instructor: 'Instructor',
  program_director: 'Program Director',
  volunteer_instructor: 'Volunteer Instructor',
  agency_observer: 'Agency Observer',
  student: 'Student',
  guest: 'Guest',
  pending: 'Pending Approval',
};

export const ROLE_COLORS: Record<Role, string> = {
  superadmin: 'bg-purple-600 text-white',
  admin: 'bg-red-600 text-white',
  lead_instructor: 'bg-blue-600 text-white',
  agency_liaison: 'bg-orange-600 text-white',
  instructor: 'bg-green-600 text-white',
  program_director: 'bg-amber-600 text-white',
  volunteer_instructor: 'bg-teal-600 text-white',
  agency_observer: 'bg-slate-600 text-white',
  student: 'bg-cyan-600 text-white',
  guest: 'bg-gray-500 text-white',
  pending: 'bg-yellow-500 text-white',
};

// Protected superadmin emails - cannot be demoted
export const PROTECTED_SUPERADMINS = [
  'bhartnell@pmi.edu',
  'jlomonaco@pmi.edu',
];

// ============================================
// Permission Check Functions
// ============================================

export function getRoleLevel(role: Role | string): number {
  return ROLE_LEVELS[role as Role] || 0;
}

export function hasMinRole(userRole: Role | string, requiredRole: Role): boolean {
  return getRoleLevel(userRole) >= ROLE_LEVELS[requiredRole];
}

export function canAccessAdmin(role: Role | string): boolean {
  return getRoleLevel(role) >= ROLE_LEVELS.admin;
}

export function canManageUsers(role: Role | string): boolean {
  return getRoleLevel(role) >= ROLE_LEVELS.admin;
}

export function canAssignRole(currentRole: Role | string, targetRole: Role): boolean {
  // Can only assign roles lower than your own
  // Exception: superadmin can assign any role
  if (currentRole === 'superadmin') return true;
  return getRoleLevel(currentRole) > ROLE_LEVELS[targetRole];
}

export function canModifyUser(currentRole: Role | string, targetRole: Role | string): boolean {
  // Can't modify users at or above your level (except superadmin)
  if (currentRole === 'superadmin') return true;
  return getRoleLevel(currentRole) > getRoleLevel(targetRole);
}

export function canDeleteUsers(role: Role | string): boolean {
  return role === 'superadmin';
}

export function canDeleteScenarios(role: Role | string): boolean {
  return getRoleLevel(role) >= ROLE_LEVELS.lead_instructor;
}

export function canCreateScenarios(role: Role | string): boolean {
  return getRoleLevel(role) >= ROLE_LEVELS.instructor;
}

export function canCreateLabDays(role: Role | string): boolean {
  return getRoleLevel(role) >= ROLE_LEVELS.instructor;
}

export function canManageCohorts(role: Role | string): boolean {
  return getRoleLevel(role) >= ROLE_LEVELS.lead_instructor;
}

export function canManageStudentRoster(role: Role | string): boolean {
  return getRoleLevel(role) >= ROLE_LEVELS.lead_instructor;
}

export function canViewAllCertifications(role: Role | string): boolean {
  return getRoleLevel(role) >= ROLE_LEVELS.admin;
}

export function canManageGuestAccess(role: Role | string): boolean {
  return getRoleLevel(role) >= ROLE_LEVELS.lead_instructor;
}

export function canManageContent(role: Role | string): boolean {
  // lead_instructor+ can manage scenarios, cohorts, lab days, students
  return getRoleLevel(role) >= ROLE_LEVELS.lead_instructor;
}

export function canAccessSystemSettings(role: Role | string): boolean {
  return role === 'superadmin';
}

export function canAccessClinical(role: Role | string): boolean {
  // Clinical & Internship section - admin, lead_instructor, superadmin
  return getRoleLevel(role) >= ROLE_LEVELS.lead_instructor;
}

export function canEditClinical(role: Role | string): boolean {
  // Can edit preceptors, internships, meetings - lead_instructor+
  return getRoleLevel(role) >= ROLE_LEVELS.lead_instructor;
}

export function canViewPreceptors(role: Role | string): boolean {
  // All authenticated users can view preceptors (per permission matrix)
  return getRoleLevel(role) >= ROLE_LEVELS.instructor;
}

export function isSuperadmin(role: Role | string): boolean {
  return role === 'superadmin';
}

export function isProtectedSuperadmin(email: string): boolean {
  return PROTECTED_SUPERADMINS.includes(email.toLowerCase());
}

// ============================================
// Role Options for Dropdowns
// ============================================

export function getAssignableRoles(currentRole: Role | string): Role[] {
  if (currentRole === 'superadmin') {
    return ['superadmin', 'admin', 'lead_instructor', 'agency_liaison', 'instructor', 'volunteer_instructor', 'program_director', 'agency_observer', 'student', 'guest', 'pending'];
  }
  if (currentRole === 'admin') {
    // Admins can assign up to lead_instructor — NOT admin or superadmin
    return ['lead_instructor', 'agency_liaison', 'instructor', 'volunteer_instructor', 'program_director', 'agency_observer', 'student', 'guest', 'pending'];
  }
  return [];
}

/**
 * Check if user is a student (has student role)
 */
export function isStudent(role: Role | string): boolean {
  return role === 'student';
}

/**
 * Check if user can access the student portal
 * Only students can access the student portal
 */
export function canAccessStudentPortal(role: Role | string): boolean {
  return role === 'student';
}

/**
 * Check if a user has a pending role (awaiting approval)
 */
export function isPendingRole(role: Role | string): boolean {
  return role === 'pending';
}

/**
 * Check if a user can access the main app features (not pending)
 * Pending users can only see their profile and a "pending approval" message
 */
export function canAccessApp(role: Role | string): boolean {
  return getRoleLevel(role) >= ROLE_LEVELS.guest;
}

/**
 * Check if user can access scheduling features (availability, shifts)
 * Available to instructors, volunteer instructors, and above
 */
export function canAccessScheduling(role: Role | string): boolean {
  return getRoleLevel(role) >= ROLE_LEVELS.volunteer_instructor && role !== 'student' && role !== 'program_director';
}

/**
 * Check if user can view lab schedules
 * Volunteer instructors can view but not modify
 */
export function canViewLabSchedule(role: Role | string): boolean {
  return getRoleLevel(role) >= ROLE_LEVELS.volunteer_instructor && role !== 'student' && role !== 'program_director';
}

/**
 * Check if user can modify lab schedules (create/edit lab days)
 * Volunteer instructors cannot - instructors and above only
 */
export function canModifyLabSchedule(role: Role | string): boolean {
  return getRoleLevel(role) >= ROLE_LEVELS.instructor;
}

/**
 * Check if user can view the affiliations page
 * Program directors get access, plus lead_instructor and above
 */
export function canAccessAffiliations(role: Role | string): boolean {
  return role === 'program_director' || hasMinRole(role, 'lead_instructor');
}

// ============================================
// LVFR AEMT Access Helpers
// ============================================

/**
 * Check if user can access the LVFR AEMT section (read).
 * Returns true for: agency_observer, agency_liaison, instructor+, admin, superadmin
 */
export function canAccessLVFR(role: Role | string): boolean {
  return role === 'agency_observer' || role === 'agency_liaison' || hasMinRole(role, 'instructor');
}

/**
 * Check if user can edit LVFR AEMT data (write).
 * Returns true for: instructor+, admin, superadmin (NOT agency_observer, NOT agency_liaison)
 * Agency roles are strictly READ-ONLY despite their numeric level.
 */
export function canEditLVFR(role: Role | string): boolean {
  if (isAgencyRole(role)) return false;
  return hasMinRole(role, 'instructor');
}

/**
 * Check if user has an agency role (liaison or observer).
 * These roles are strictly read-only on all endpoints.
 */
export function isAgencyRole(role: Role | string): boolean {
  return role === 'agency_liaison' || role === 'agency_observer';
}

/**
 * Check if current user is a student role (LVFR student check is cohort-based,
 * but this helper quickly identifies student-role users who may be LVFR students).
 */
export function isLVFRStudent(role: Role | string): boolean {
  return role === 'student';
}

/**
 * Check if user can create/edit/delete affiliations
 * Program directors get full CRUD, plus admin and above
 */
export function canEditAffiliations(role: Role | string): boolean {
  return role === 'program_director' || hasMinRole(role, 'admin');
}

// ============================================
// UI Helpers
// ============================================

export function getRoleBadgeClasses(role: Role | string): string {
  return ROLE_COLORS[role as Role] || 'bg-gray-400 text-white';
}

export function getRoleLabel(role: Role | string): string {
  return ROLE_LABELS[role as Role] || role;
}

// ============================================
// Endorsement Badge Helpers (for UI display)
// ============================================

export const ENDORSEMENT_BADGE_CONFIG: Record<string, { abbrev: string; label: string; bg: string; text: string }> = {
  director: { abbrev: 'DIR', label: 'Director', bg: 'bg-amber-100 dark:bg-amber-900/30', text: 'text-amber-800 dark:text-amber-300' },
  mentor: { abbrev: 'MNT', label: 'Mentor', bg: 'bg-violet-100 dark:bg-violet-900/30', text: 'text-violet-800 dark:text-violet-300' },
  preceptor: { abbrev: 'PRC', label: 'Preceptor', bg: 'bg-cyan-100 dark:bg-cyan-900/30', text: 'text-cyan-800 dark:text-cyan-300' },
};

/**
 * Get the short badge text for an endorsement
 * e.g., "Program Director" -> "PD", "Clinical Director" -> "CD"
 */
export function getEndorsementBadgeText(endorsementType: string, title?: string | null): string {
  if (endorsementType === 'director' && title) {
    if (title.includes('Program')) return 'PD';
    if (title.includes('Clinical')) return 'CD';
  }
  return ENDORSEMENT_BADGE_CONFIG[endorsementType]?.abbrev || endorsementType.toUpperCase().slice(0, 3);
}

export function getEndorsementBadgeClasses(endorsementType: string): string {
  const config = ENDORSEMENT_BADGE_CONFIG[endorsementType];
  return config ? `${config.bg} ${config.text}` : 'bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400';
}

// ============================================
// FERPA Data Access Permissions
// ============================================

// FERPA Classification:
// - Directory Information (can be shared): name, cohort, enrollment status, dates
// - Protected Educational Records (restricted): email, agency, assessments, notes

export const DATA_PERMISSIONS = {
  // Who can see student email
  studentEmail: ['superadmin', 'admin', 'lead_instructor'] as Role[],

  // Who can see student agency/employer
  studentAgency: ['superadmin', 'admin', 'lead_instructor', 'agency_liaison', 'instructor'] as Role[],

  // Who can see learning styles
  learningStyles: ['superadmin', 'admin', 'lead_instructor', 'agency_liaison', 'instructor'] as Role[],

  // Who can see performance notes
  performanceNotes: ['superadmin', 'admin', 'lead_instructor', 'agency_liaison', 'instructor'] as Role[],

  // Who can see skill assessments
  skillAssessments: ['superadmin', 'admin', 'lead_instructor', 'agency_liaison', 'instructor'] as Role[],

  // Who can see student full records (all data)
  studentFullRecord: ['superadmin', 'admin', 'lead_instructor', 'agency_liaison', 'instructor'] as Role[],

  // Who can see directory info only (name, cohort, status)
  studentDirectoryInfo: ['superadmin', 'admin', 'lead_instructor', 'agency_liaison', 'instructor', 'agency_observer', 'guest'] as Role[],

  // Who can view audit logs
  auditLogs: ['superadmin'] as Role[],

  // Who can export student data
  exportStudentData: ['superadmin', 'admin', 'lead_instructor'] as Role[],
};

export type DataPermissionType = keyof typeof DATA_PERMISSIONS;

export function canAccessData(userRole: Role | string, dataType: DataPermissionType): boolean {
  const allowedRoles = DATA_PERMISSIONS[dataType];
  return allowedRoles.includes(userRole as Role);
}

// ============================================
// Student Data Sanitization (FERPA Compliance)
// ============================================

export interface StudentRecord {
  id: string;
  first_name: string;
  last_name: string;
  email?: string | null;
  cohort_id?: string | null;
  agency?: string | null;
  photo_url?: string | null;
  notes?: string | null;
  status?: string;
  cohort?: any;
  learning_style?: any;
  [key: string]: any;
}

export interface SanitizedStudent {
  id: string;
  first_name: string;
  last_name: string;
  cohort_id?: string | null;
  cohort?: any;
  status?: string;
  email?: string | null;
  agency?: string | null;
  photo_url?: string | null;
  notes?: string | null;
  learning_style?: any;
  [key: string]: any;
}

/**
 * Sanitizes student data based on user role for FERPA compliance.
 * Guests only see directory information (name, cohort).
 * Instructors see most data except sensitive notes.
 * Lead instructors and above see everything.
 */
export function sanitizeStudentForRole(student: StudentRecord, userRole: Role | string): SanitizedStudent {
  // Always include directory information (FERPA allows this)
  const sanitized: SanitizedStudent = {
    id: student.id,
    first_name: student.first_name,
    last_name: student.last_name,
    cohort_id: student.cohort_id,
    status: student.status,
  };

  // --- Agency Observer: directory info + basic status ONLY ---
  // No email, no notes, no agency details, no photos, no learning styles
  if (userRole === 'agency_observer') {
    return sanitized;
  }

  // --- Agency Liaison: similar to instructor but strip internal notes ---
  if (userRole === 'agency_liaison') {
    // Include cohort info (directory info)
    if (student.cohort) {
      sanitized.cohort = student.cohort;
    }
    // Include photo (helps identify students)
    sanitized.photo_url = student.photo_url;
    // Include agency
    sanitized.agency = student.agency;
    // Include learning styles
    if (student.learning_style) {
      sanitized.learning_style = student.learning_style;
    }
    // NO email (agency liaisons don't need student email)
    // NO internal notes (strip for agency views)
    return sanitized;
  }

  // --- Standard role-based sanitization for all other roles ---

  // Include cohort info if present (directory info)
  if (student.cohort) {
    sanitized.cohort = student.cohort;
  }

  // Add photo URL for instructors+ (helps identify students)
  if (canAccessData(userRole, 'studentAgency')) {
    sanitized.photo_url = student.photo_url;
  }

  // Add email if permitted
  if (canAccessData(userRole, 'studentEmail')) {
    sanitized.email = student.email;
  }

  // Add agency if permitted
  if (canAccessData(userRole, 'studentAgency')) {
    sanitized.agency = student.agency;
  }

  // Add learning styles if permitted
  if (canAccessData(userRole, 'learningStyles') && student.learning_style) {
    sanitized.learning_style = student.learning_style;
  }

  // Add notes if permitted (performance data)
  if (canAccessData(userRole, 'performanceNotes')) {
    sanitized.notes = student.notes;
  }

  // Pass through any additional fields for full access roles
  if (canAccessData(userRole, 'studentFullRecord')) {
    // Include team lead counts and other non-PII operational data
    if (student.team_lead_count !== undefined) {
      sanitized.team_lead_count = student.team_lead_count;
    }
    if (student.last_team_lead_date !== undefined) {
      sanitized.last_team_lead_date = student.last_team_lead_date;
    }
  }

  return sanitized;
}

/**
 * Sanitizes an array of students based on user role
 */
export function sanitizeStudentsForRole(students: StudentRecord[], userRole: Role | string): SanitizedStudent[] {
  return students.map(student => sanitizeStudentForRole(student, userRole));
}
